import{_ as e,o as r,c as a,ag as n}from"./chunks/framework.6MCaaFDc.js";const p=JSON.parse('{"title":"Internet & the World Wide Web","description":"","frontmatter":{},"headers":[],"relativePath":"theory/internet/internet-www.md","filePath":"theory/internet/internet-www.md"}'),s={name:"theory/internet/internet-www.md"};function o(i,t,d,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="internet-the-world-wide-web" tabindex="-1">Internet &amp; the World Wide Web <a class="header-anchor" href="#internet-the-world-wide-web" aria-label="Permalink to &quot;Internet &amp; the World Wide Web&quot;">​</a></h1><p>The internet and the web are not the same thing. The internet is the infrastructure — billions of computers connected by cables, fibre, and wireless links. The web is one service that runs on top of it. Understanding both is core Paper 2 knowledge.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Internet basics (IP, domain names, ISPs, WWW) are introduced in Grade 10. Web evolution (1.0/2.0/3.0), HTML, and internet services extend into Grade 11 and 12.</p></div><hr><h2 id="internet-vs-world-wide-web" tabindex="-1">Internet vs World Wide Web <a class="header-anchor" href="#internet-vs-world-wide-web" aria-label="Permalink to &quot;Internet vs World Wide Web&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Internet</th><th>World Wide Web</th></tr></thead><tbody><tr><td><strong>Definition</strong></td><td>Global network of interconnected computers</td><td>System of web pages and resources accessible via the internet using HTTP/HTTPS</td></tr><tr><td><strong>Type</strong></td><td>Physical + logical infrastructure</td><td>A service/application that runs ON the internet</td></tr><tr><td><strong>Protocol</strong></td><td>TCP/IP</td><td>HTTP / HTTPS</td></tr><tr><td><strong>Access</strong></td><td>Many services (email, FTP, streaming, gaming)</td><td>Web pages viewed in browsers</td></tr><tr><td><strong>Invented</strong></td><td>1969 (ARPANET)</td><td>1991 (Tim Berners-Lee)</td></tr></tbody></table><blockquote><p>The internet is the road. The web is one of many vehicles on it.<br> Other &quot;vehicles&quot; (services on the internet): email, FTP, VoIP, online gaming, cloud storage.</p></blockquote><hr><h2 id="how-the-internet-works" tabindex="-1">How the Internet Works <a class="header-anchor" href="#how-the-internet-works" aria-label="Permalink to &quot;How the Internet Works&quot;">​</a></h2><h3 id="ip-addresses" tabindex="-1">IP Addresses <a class="header-anchor" href="#ip-addresses" aria-label="Permalink to &quot;IP Addresses&quot;">​</a></h3><p>Every device on the internet has an <strong>IP address</strong> — a unique numerical label that identifies it.</p><p><strong>IPv4:</strong> 32-bit address — written as four groups of numbers 0–255<br> Example: <code>196.22.145.100</code><br> Total addresses: ~4.3 billion (running out)</p><p><strong>IPv6:</strong> 128-bit address — written in hexadecimal groups<br> Example: <code>2001:0db8:85a3:0000:0000:8a2e:0370:7334</code><br> Total addresses: 340 undecillion (essentially unlimited)</p><h3 id="domain-names" tabindex="-1">Domain Names <a class="header-anchor" href="#domain-names" aria-label="Permalink to &quot;Domain Names&quot;">​</a></h3><p>IP addresses are hard to remember. <strong>Domain names</strong> are human-readable addresses:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>www.google.com</span></span>
<span class="line"><span> |      |    |</span></span>
<span class="line"><span>www   google  com</span></span>
<span class="line"><span>|       |      |</span></span>
<span class="line"><span>subdomain  domain  TLD</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>TLD = Top Level Domain:</strong></p><table tabindex="0"><thead><tr><th>TLD</th><th>Use</th></tr></thead><tbody><tr><td><code>.com</code></td><td>Commercial organisations</td></tr><tr><td><code>.org</code></td><td>Non-profit organisations</td></tr><tr><td><code>.gov</code></td><td>Government</td></tr><tr><td><code>.edu</code> / <code>.ac</code></td><td>Educational institutions</td></tr><tr><td><code>.co.za</code></td><td>South African commercial</td></tr><tr><td><code>.za</code></td><td>South Africa (country code)</td></tr><tr><td><code>.net</code></td><td>Network services</td></tr></tbody></table><h3 id="dns-resolution" tabindex="-1">DNS Resolution <a class="header-anchor" href="#dns-resolution" aria-label="Permalink to &quot;DNS Resolution&quot;">​</a></h3><p>When you type <code>www.school.co.za</code>:</p><ol><li>Your device checks its local <strong>DNS cache</strong></li><li>Asks your router → ISP&#39;s DNS server</li><li>DNS server returns the IP address: <code>196.22.145.100</code></li><li>Your browser connects to that IP address</li></ol><h3 id="isp-—-internet-service-provider" tabindex="-1">ISP — Internet Service Provider <a class="header-anchor" href="#isp-—-internet-service-provider" aria-label="Permalink to &quot;ISP — Internet Service Provider&quot;">​</a></h3><p>An <strong>ISP</strong> is a company that provides internet access — Telkom, Vodacom, MTN, Afrihost, etc.</p><p>The ISP:</p><ul><li>Connects your network to the internet backbone</li><li>Assigns IP addresses (via DHCP)</li><li>Provides DNS servers</li><li>Manages your bandwidth</li></ul><hr><h2 id="web-technologies" tabindex="-1">Web Technologies <a class="header-anchor" href="#web-technologies" aria-label="Permalink to &quot;Web Technologies&quot;">​</a></h2><h3 id="url-—-uniform-resource-locator" tabindex="-1">URL — Uniform Resource Locator <a class="header-anchor" href="#url-—-uniform-resource-locator" aria-label="Permalink to &quot;URL — Uniform Resource Locator&quot;">​</a></h3><p>A URL is the complete address of a resource on the web:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.school.co.za:443/it/notes.html?topic=binary#section1</span></span>
<span class="line"><span>  |         |            |    |      |           |          |</span></span>
<span class="line"><span>protocol  domain       port  path  file       query     anchor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><table tabindex="0"><thead><tr><th>Part</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td>Protocol</td><td><code>https://</code></td><td>How to retrieve the resource</td></tr><tr><td>Domain</td><td><code>www.school.co.za</code></td><td>Which server</td></tr><tr><td>Port</td><td><code>:443</code></td><td>Which service on the server (optional — defaults apply)</td></tr><tr><td>Path</td><td><code>/it/</code></td><td>Folder/directory on the server</td></tr><tr><td>File</td><td><code>notes.html</code></td><td>Specific resource</td></tr><tr><td>Query</td><td><code>?topic=binary</code></td><td>Parameters passed to the server</td></tr><tr><td>Anchor</td><td><code>#section1</code></td><td>Jump to section within the page</td></tr></tbody></table><h3 id="web-browser" tabindex="-1">Web Browser <a class="header-anchor" href="#web-browser" aria-label="Permalink to &quot;Web Browser&quot;">​</a></h3><p>A <strong>web browser</strong> is the application that retrieves and displays web content:</p><ul><li>Google Chrome, Firefox, Safari, Microsoft Edge</li><li>Interprets HTML, CSS, JavaScript</li><li>Communicates using HTTP/HTTPS</li></ul><h3 id="web-server" tabindex="-1">Web Server <a class="header-anchor" href="#web-server" aria-label="Permalink to &quot;Web Server&quot;">​</a></h3><p>A <strong>web server</strong> is a computer that stores and serves web pages:</p><ul><li>Runs server software (Apache, Nginx, IIS)</li><li>Listens on port 80 (HTTP) or 443 (HTTPS)</li><li>Receives browser requests and returns HTML/CSS/JS files</li></ul><hr><h2 id="web-evolution" tabindex="-1">Web Evolution <a class="header-anchor" href="#web-evolution" aria-label="Permalink to &quot;Web Evolution&quot;">​</a></h2><div class="tip custom-block github-alert"><p class="custom-block-title">Grade 11 — Extension</p><p>Web 1.0/2.0/3.0 classification extended in Grade 11.</p></div><h3 id="web-1-0-—-read-only-mid-1990s-–-early-2000s" tabindex="-1">Web 1.0 — Read Only (mid-1990s – early 2000s) <a class="header-anchor" href="#web-1-0-—-read-only-mid-1990s-–-early-2000s" aria-label="Permalink to &quot;Web 1.0 — Read Only (mid-1990s – early 2000s)&quot;">​</a></h3><ul><li>Static HTML pages</li><li>Content created only by website owners</li><li>No user interaction or accounts</li><li>Users read but don&#39;t contribute</li><li>Examples: first business websites, early news sites</li></ul><h3 id="web-2-0-—-read-write-2004-–-present" tabindex="-1">Web 2.0 — Read-Write (2004 – present) <a class="header-anchor" href="#web-2-0-—-read-write-2004-–-present" aria-label="Permalink to &quot;Web 2.0 — Read-Write (2004 – present)&quot;">​</a></h3><ul><li>Dynamic, interactive content</li><li>User-generated content</li><li>Social media, comments, wikis, sharing</li><li>Examples: Facebook, YouTube, Wikipedia, Twitter, Google Docs</li></ul><p><strong>Key features:</strong></p><ul><li>AJAX (update parts of page without full reload)</li><li>APIs (applications communicate with each other)</li><li>Blogs, podcasts, user reviews</li><li>Cloud computing</li></ul><h3 id="web-3-0-—-semantic-web-emerging" tabindex="-1">Web 3.0 — Semantic Web (emerging) <a class="header-anchor" href="#web-3-0-—-semantic-web-emerging" aria-label="Permalink to &quot;Web 3.0 — Semantic Web (emerging)&quot;">​</a></h3><ul><li>Intelligent, personalised, context-aware content</li><li>Machine-readable data — computers understand meaning, not just words</li><li>Decentralised (blockchain-based)</li><li>Personalised search based on understanding your context and preferences</li><li>Examples: AI assistants, personalised recommendations, IoT integration</li></ul><hr><h2 id="static-vs-dynamic-websites" tabindex="-1">Static vs Dynamic Websites <a class="header-anchor" href="#static-vs-dynamic-websites" aria-label="Permalink to &quot;Static vs Dynamic Websites&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Static</th><th>Dynamic</th></tr></thead><tbody><tr><td><strong>Content</strong></td><td>Fixed HTML files — same for everyone</td><td>Generated per request — customised per user</td></tr><tr><td><strong>Server</strong></td><td>Just serves files</td><td>Runs server-side code (PHP, Python, Node.js)</td></tr><tr><td><strong>Database</strong></td><td>Not used</td><td>Usually used</td></tr><tr><td><strong>Update</strong></td><td>Developer edits HTML files</td><td>CMS or user input changes database</td></tr><tr><td><strong>Examples</strong></td><td>Simple brochure sites</td><td>Facebook, Gmail, online banking</td></tr></tbody></table><hr><h2 id="intranet-vs-extranet-vs-internet" tabindex="-1">Intranet vs Extranet vs Internet <a class="header-anchor" href="#intranet-vs-extranet-vs-internet" aria-label="Permalink to &quot;Intranet vs Extranet vs Internet&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Intranet</th><th>Extranet</th><th>Internet</th></tr></thead><tbody><tr><td><strong>Who can access</strong></td><td>Internal users only</td><td>Authorised external parties</td><td>Anyone</td></tr><tr><td><strong>Security</strong></td><td>Inside company firewall</td><td>Controlled external access</td><td>Public</td></tr><tr><td><strong>Example</strong></td><td>Company internal portal</td><td>Supplier order system</td><td>www</td></tr></tbody></table><hr><h2 id="cloud-computing" tabindex="-1">Cloud Computing <a class="header-anchor" href="#cloud-computing" aria-label="Permalink to &quot;Cloud Computing&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">Grade 12 — Mastery</p><p>Cloud computing and online services are a Grade 12 focus.</p></div><p><strong>Cloud computing</strong> = accessing computing resources (storage, software, processing) over the internet instead of locally.</p><p><strong>Service models:</strong></p><table tabindex="0"><thead><tr><th>Model</th><th>What you get</th><th>Example</th></tr></thead><tbody><tr><td><strong>IaaS</strong> (Infrastructure as a Service)</td><td>Rent hardware — virtual servers, storage</td><td>Amazon AWS, Microsoft Azure</td></tr><tr><td><strong>PaaS</strong> (Platform as a Service)</td><td>Rent a development platform</td><td>Google App Engine</td></tr><tr><td><strong>SaaS</strong> (Software as a Service)</td><td>Rent software — pay per use</td><td>Microsoft 365, Google Workspace, Netflix</td></tr></tbody></table><p><strong>Advantages of cloud:</strong></p><ul><li>Access from any device, anywhere</li><li>Automatic backups and updates</li><li>Scale up/down without hardware purchases</li><li>Pay only for what you use</li></ul><p><strong>Disadvantages of cloud:</strong></p><ul><li>Requires internet connectivity</li><li>Data security and privacy concerns</li><li>Ongoing subscription costs</li><li>Vendor lock-in (dependency on one provider)</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Internet</strong></td><td>Global network of interconnected computers</td></tr><tr><td><strong>WWW</strong></td><td>World Wide Web — web pages accessible via HTTP/HTTPS</td></tr><tr><td><strong>IP address</strong></td><td>Unique numerical identifier for a device on a network</td></tr><tr><td><strong>IPv4/IPv6</strong></td><td>Version 4 (32-bit) / Version 6 (128-bit) IP address formats</td></tr><tr><td><strong>Domain name</strong></td><td>Human-readable address (www.google.com)</td></tr><tr><td><strong>TLD</strong></td><td>Top Level Domain — the last part of a domain (.com, .za)</td></tr><tr><td><strong>DNS</strong></td><td>System translating domain names to IP addresses</td></tr><tr><td><strong>URL</strong></td><td>Full address of a resource on the web</td></tr><tr><td><strong>ISP</strong></td><td>Internet Service Provider — company providing internet access</td></tr><tr><td><strong>Browser</strong></td><td>Application that retrieves and displays web content</td></tr><tr><td><strong>Web server</strong></td><td>Computer storing and serving web pages</td></tr><tr><td><strong>Static website</strong></td><td>Fixed HTML — same for all visitors</td></tr><tr><td><strong>Dynamic website</strong></td><td>Server-generated — customised per user/request</td></tr><tr><td><strong>Cloud computing</strong></td><td>Computing resources delivered over the internet</td></tr><tr><td><strong>SaaS</strong></td><td>Software as a Service — software accessed via internet</td></tr><tr><td><strong>Web 2.0</strong></td><td>Interactive, user-generated content web</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Explain the difference between the Internet and the World Wide Web&quot;</strong> — internet = infrastructure; web = service running on internet using HTTP to access web pages</p></li><li><p><strong>&quot;What is an IP address? What is the purpose of DNS?&quot;</strong> — unique device identifier; DNS translates domain names to IP addresses</p></li><li><p><strong>&quot;Explain the difference between Web 1.0 and Web 2.0&quot;</strong> — 1.0 = static, read-only; 2.0 = interactive, user-generated content, social media</p></li><li><p><strong>&quot;Give TWO advantages of cloud computing&quot;</strong> — access anywhere, automatic backups, scalable, no hardware to buy/maintain</p></li><li><p><strong>&quot;What is the difference between an intranet and the internet?&quot;</strong> — intranet: private internal network; internet: public global network</p></li></ol></div>`,70)])])}const b=e(s,[["render",o]]);export{p as __pageData,b as default};
